return [
  {
    json: {
      test_name: "Hugging Face Embedding",
      prompt: "This is a test sentence to convert into a vector embedding.",
      model_preference: "embedding"
    }
  }
];

const items = $input.all();
const summary = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;
  // Match back to the original test inputs via paired item context
  const originalTest = $('Generate Test Cases').all()[i]?.json || {};

  let status = "🟢 PASS";
  let notes = "Model responded successfully.";

  if (item.error || !item.response || (typeof item.response === 'string' && item.response.startsWith("ERROR:"))) {
    status = "🔴 FAIL";
    notes = item.error?.message || item.response || "Unknown API or Network error.";
  }

  // Enhanced array validation for Hugging Face embeddings
  let responseSample = "N/A";
  if (originalTest.model_preference === 'embedding' && Array.isArray(item.response)) {
    // Extract the vector dimensions from the first array element
    const dimensions = Array.isArray(item.response[0]) ? item.response[0].length : item.response.length;
    responseSample = `✅ Vector Array generated (Dimensions: ${dimensions})`;
  } else {
    responseSample = String(item.response).substring(0, 60);
  }

  summary.push({
    json: {
      test_name: originalTest.test_name,
      model_preference: originalTest.model_preference,
      model_used: item.model_used || 'all-MiniLM-L6-v2',
      status: status,
      latency: item.latency_ms ? `${item.latency_ms}ms` : 'N/A',
      response_sample: responseSample,
      error_details: notes
    }
  });
}

return summary;
